     * Tests Main.generateTests with multiple test cases for non-deterministic coverage.
     * (2.0 pts)
     */
    @Test
    void testMultipleCasesNonDeterministic() throws IOException, InvalidConfigException, InterruptedException {
        // Create a config
        String config = """
            {
                "fname": "double",
                "types": ["int"],
